// Capture row counts from both delete operations
const draftsResult = $input.all()[0].json;
const dismissalsResult = $input.all()[1]?.json;

const nDrafts = Array.isArray(draftsResult) ? draftsResult.length : 0;
const nDismissals = Array.isArray(dismissalsResult) ? dismissalsResult.length : 0;
const total = nDrafts + nDismissals;

console.log(`[CRM Nightly Cleanup] Deleted ${nDrafts} expired entity_drafts + ${nDismissals} expired crm_action_dismissals (total: ${total})`);

return [{ json: { n_drafts: nDrafts, n_dismissals: nDismissals, total, run_at: new Date().toISOString(), notify: total > 100 } }];
